mapper.select:
SELECT R.RES_ID, R.COM_ID, R.RES_CODE, R.RES_NAME, R.RES_TYPE, R.QUANTITY, R.LOCATION, R.CAPACITY, R.RES_STATUS, E.EMP_ID AS managerEmpId, E.EMP_NAME AS managerEmpName, E.EMP_NO AS managerEmpNo, EP.POS_ID AS managerPosId, EP.POS_NAME AS managerPosName, R.REMARK, R.CREATED_AT, R.UPDATED_AT, COUNT(RV.REV_ID) AS RESV_COUNT FROM COM_RESOURCE R LEFT JOIN RESERVATION RV ON R.RES_ID = RV.RES_ID LEFT JOIN EMPLOYEE E ON R.MANAGER_EMP_ID = E.EMP_ID LEFT JOIN EMP_POSITION EP ON EP.POS_ID = E.POS_ID WHERE R.com_id = #{comId}
AND (R.res_name LIKE '%' || #{keyword} || '%' OR R.res_code LIKE '%' || #{keyword} || '%')
AND R.res_type = #{resType}
AND R.RES_STATUS = #{resStatus}
GROUP BY R.RES_ID, R.COM_ID, R.RES_CODE, R.RES_NAME, R.RES_TYPE, R.QUANTITY, R.LOCATION, R.CAPACITY, R.RES_STATUS, E.EMP_ID, E.EMP_NAME, E.EMP_NO, EP.POS_ID, EP.POS_NAME, R.REMARK, R.CREATED_AT, R.UPDATED_AT ORDER BY R.res_id DESC OFFSET #{pstartno} ROWS FETCH NEXT #{onepagelist} ROWS ONLY

        SELECT COUNT(*)
        FROM COM_RESOURCE R
        WHERE R.com_id = #{comId}

			AND (R.res_name LIKE '%' || #{keyword} || '%'
			     OR R.res_code LIKE '%' || #{keyword} || '%')


            AND R.res_type = #{resType}


            AND R.RES_STATUS = #{resStatus}

mapper.insert:
INSERT INTO com_resource (
    res_id, com_id, res_code, res_name, res_type, quantity,
    location, capacity, res_status, manager_emp_id, remark
)
VALUES (
    seq_com_resource.NEXTVAL, #{comId}, #{resCode}, #{resName}, #{resType}, #{quantity},
    #{location}, #{capacity, jdbcType=INTEGER}, #{resStatus}, #{managerEmpId, jdbcType=VARCHAR}, #{remark}
)

mapper.update:
UPDATE com_resource
res_name = #{resName}, res_type = #{resType}, quantity = #{quantity}, location = #{location}, capacity = #{capacity}, res_status = #{resStatus}, manager_emp_id = #{managerEmpId}, remark = #{remark},
WHERE res_id = #{resId}

